let gliederung = [];
try { gliederung = $('Sheets — Gliederung lesen').all().map(i => i.json); } catch(e) {}

let analyse = [];
try { analyse = $('Sheets — Analyse lesen').all().map(i => i.json); } catch(e) {}

const spreadsheetId = $('WF6 Variablen').first().json.spreadsheet_id;

if (gliederung.length === 0) {
  return [{ json: { error: 'Keine Gliederung gefunden', spreadsheet_id: spreadsheetId } }];
}

// Normalize: handle missing headers by mapping columns by index
const normalized = gliederung.map(row => {
  if (row.ebene && row.ueberschrift) return row;
  // If no named columns, map by key order (Google Sheets returns as col0, col1, etc. or first-row values)
  const vals = Object.values(row);
  // Skip row_number if present
  const keys = Object.keys(row);
  const startIdx = keys[0] === 'row_number' ? 1 : 0;
  return {
    position: vals[startIdx] || '',
    ebene: vals[startIdx + 1] || '',
    ueberschrift: vals[startIdx + 2] || '',
    typ: vals[startIdx + 3] || '',
    basiert_auf: vals[startIdx + 4] || '',
    stichpunkte: vals[startIdx + 5] || '',
    freigabe: vals[startIdx + 6] || 'nein'
  };
}).filter(row => row.ebene && ['h1', 'h2', 'h3', 'h4'].includes(row.ebene.toLowerCase()));

// Skip header row if it got included as data
const filtered = normalized.filter(row => row.ebene !== 'ebene');

// Find latest complete gliederung: last h1 with position 1
let startIndex = 0;
for (let i = filtered.length - 1; i >= 0; i--) {
  if (filtered[i].ebene === 'h1' && String(filtered[i].position) === '1') {
    startIndex = i;
    break;
  }
}
const latest = filtered.slice(startIndex);

// Curate: ALL commodity + 3 luecke + 2 unique_angle + 2 expert_take
const hPriority = (ebene) => {
  if (ebene === 'h1') return 1;
  if (ebene === 'h2') return 2;
  if (ebene === 'h3') return 3;
  return 4;
};

const commodity = latest.filter(g => g.basiert_auf === 'commodity');
const luecke = latest.filter(g => g.basiert_auf === 'luecke').sort((a, b) => hPriority(a.ebene) - hPriority(b.ebene)).slice(0, 3);
const uniqueAngle = latest.filter(g => g.basiert_auf === 'unique_angle').sort((a, b) => hPriority(a.ebene) - hPriority(b.ebene)).slice(0, 2);
const expertTake = latest.filter(g => g.basiert_auf === 'expert_take').sort((a, b) => hPriority(a.ebene) - hPriority(b.ebene)).slice(0, 2);

// Combine and sort by position
const selected = [...commodity, ...luecke, ...uniqueAngle, ...expertTake]
  .sort((a, b) => Number(a.position) - Number(b.position));

if (selected.length === 0) {
  return [{ json: { error: 'Keine passenden Sektionen nach Kuratierung', spreadsheet_id: spreadsheetId } }];
}

// Build context
const outlineContext = selected.map(s =>
  `${s.ebene}: ${s.ueberschrift} (${s.typ}) - ${s.stichpunkte}`
).join('\n');

const analyseContext = analyse.map(a =>
  `[${a.kategorie}] ${a.keyword_oder_thema}: ${a.details}`
).join('\n');

return selected.map(section => ({
  json: {
    position: String(section.position),
    ebene: section.ebene,
    ueberschrift: section.ueberschrift,
    typ: section.typ,
    stichpunkte: section.stichpunkte,
    basiert_auf: section.basiert_auf,
    outline_context: outlineContext,
    analyse_context: analyseContext,
    spreadsheet_id: spreadsheetId
  }
}));

