const response = $input.first().json;
const sectionData = $('Sektionen einzeln verarbeiten').first().json;

let content = '';
try {
  content = response.content?.[0]?.text || response.content || '';
} catch (e) {
  content = 'Fehler bei Content-Generierung: ' + e.message;
}

return [{
  json: {
    abschnitt: sectionData.ueberschrift,
    position: sectionData.position,
    ebene: sectionData.ebene,
    content_raw: content,
    content_humanized: '',
    content_final: '',
    spreadsheet_id: sectionData.spreadsheet_id
  }
}];
